/* Doha Clock Override - ClearTouch Media */
(function() {
  function updateDohaClock() {
    try {
      const now = new Date();
      const formatter = new Intl.DateTimeFormat('en-US', {
        timeZone: 'Asia/Qatar',
        hour: '2-digit',
        minute: '2-digit',
        hour12: true
      });
      const parts = formatter.formatToParts(now);
      const hour = parts.find(p => p.type === 'hour').value;
      const minute = parts.find(p => p.type === 'minute').value;
      const dayPeriod = parts.find(p => p.type === 'dayPeriod').value;

      const hourEl = document.getElementById('hour');
      const minuteEl = document.getElementById('minute');
      const ampmEl = document.getElementById('ampm');

      if (hourEl) hourEl.textContent = hour;
      if (minuteEl) minuteEl.textContent = minute;
      if (ampmEl) ampmEl.textContent = dayPeriod.toUpperCase();
    } catch (e) {
      console.error("Doha Clock Error:", e);
    }
  }
  
  if (document.readyState === 'complete' || document.readyState === 'interactive') {
    updateDohaClock();
  } else {
    document.addEventListener('DOMContentLoaded', updateDohaClock);
  }
  setInterval(updateDohaClock, 1000);
})();

